import{_ as a,o as e,c as o,a3 as i}from"./chunks/framework.Df0_fMVA.js";const u=JSON.parse('{"title":"Installation","description":"","frontmatter":{},"headers":[],"relativePath":"guide/installation.md","filePath":"guide/installation.md"}'),r={name:"guide/installation.md"};function s(d,t,l,n,c,h){return e(),o("div",null,[...t[0]||(t[0]=[i('<h1 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-label="Permalink to &quot;Installation&quot;">​</a></h1><h2 id="claude-code-primary" tabindex="-1">Claude Code (Primary) <a class="header-anchor" href="#claude-code-primary" aria-label="Permalink to &quot;Claude Code (Primary)&quot;">​</a></h2><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> specialist-agent</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> init</span></span></code></pre></div><p>Interactive CLI that:</p><ul><li>Detects your framework or lets you start with an empty project</li><li>Installs 35 agents (Full or Lite mode)</li><li>Configures 24 skills</li><li>Sets up native hooks (security guard, auto-dispatch, auto-format)</li></ul><h2 id="cursor" tabindex="-1">Cursor <a class="header-anchor" href="#cursor" aria-label="Permalink to &quot;Cursor&quot;">​</a></h2><p>Copy the <code>.cursor-plugin/</code> directory to your project, or install via Cursor&#39;s plugin marketplace.</p><h2 id="vs-code" tabindex="-1">VS Code <a class="header-anchor" href="#vs-code" aria-label="Permalink to &quot;VS Code&quot;">​</a></h2><p>Install via the VS Code extension marketplace or copy <code>.vscode/extension.json</code>.</p><h2 id="windsurf" tabindex="-1">Windsurf <a class="header-anchor" href="#windsurf" aria-label="Permalink to &quot;Windsurf&quot;">​</a></h2><p>Copy the <code>.windsurf/plugin.json</code> to your project root.</p><h2 id="codex" tabindex="-1">Codex <a class="header-anchor" href="#codex" aria-label="Permalink to &quot;Codex&quot;">​</a></h2><p>See <a href="/pr-preview/pr-79/guide/install-codex.html">Codex installation guide</a>.</p><h2 id="opencode" tabindex="-1">OpenCode <a class="header-anchor" href="#opencode" aria-label="Permalink to &quot;OpenCode&quot;">​</a></h2><p>See <a href="/pr-preview/pr-79/guide/install-opencode.html">OpenCode installation guide</a>.</p><h2 id="global-vs-project-install" tabindex="-1">Global vs Project Install <a class="header-anchor" href="#global-vs-project-install" aria-label="Permalink to &quot;Global vs Project Install&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Scope</th><th>Location</th><th>Use case</th></tr></thead><tbody><tr><td>Project</td><td><code>.claude/agents/</code></td><td>Framework-specific agents per project</td></tr><tr><td>Global</td><td><code>~/.claude/agents/</code></td><td>Shared agents across all projects</td></tr></tbody></table><h2 id="framework-packs" tabindex="-1">Framework Packs <a class="header-anchor" href="#framework-packs" aria-label="Permalink to &quot;Framework Packs&quot;">​</a></h2><p>Each pack includes optimized versions of @builder, @reviewer, @doctor, @migrator:</p><table tabindex="0"><thead><tr><th>Pack</th><th>Framework</th></tr></thead><tbody><tr><td><code>vue</code></td><td>Vue 3 + Composition API</td></tr><tr><td><code>react</code></td><td>React 18+ with hooks</td></tr><tr><td><code>nextjs</code></td><td>Next.js App Router / Pages</td></tr><tr><td><code>svelte</code></td><td>SvelteKit</td></tr><tr><td><code>angular</code></td><td>Angular 17+</td></tr><tr><td><code>astro</code></td><td>Astro</td></tr><tr><td><code>nuxt</code></td><td>Nuxt 3</td></tr></tbody></table><p>Empty projects get all agents with React defaults. Re-run <code>npx specialist-agent init</code> when you choose a framework.</p><h2 id="updating" tabindex="-1">Updating <a class="header-anchor" href="#updating" aria-label="Permalink to &quot;Updating&quot;">​</a></h2><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> specialist-agent</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> init</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --force</span></span></code></pre></div>',23)])])}const k=a(r,[["render",s]]);export{u as __pageData,k as default};
